head.script:
// 전역변수
scwin.params                    = $c.data.getParameter();
scwin.kcomcd                    = scwin.params.kcomcd == null ? "" : scwin.params.kcomcd;
scwin.mblno                     = scwin.params.mblno == null ? "" : scwin.params.mblno;
scwin.mhno                      = scwin.params.mhno == null ? "" : scwin.params.mhno;
scwin.bilgClntNo                = scwin.params.bilgClntNo == null ? "" : scwin.params.bilgClntNo;
scwin.strCurDate                = WebSquare.date.getCurrentServerDate();
scwin.strPreDate                = $c.date.addMonth(scwin.strCurDate, -1)
scwin.processFlag               = ""

//hidden
scwin.dtl_sellVatNo = ""
scwin.dtl_offsetVatNo = ""
scwin.hid_kcomcd = "DBEX"
scwin.txt_countRow = ""
scwin.hid_commNm = "DBEX"


//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------

scwin.onpageload = function() {

};

scwin.onUdcCompleted = function() {
	gr_invoiceCommonList.hide();

    scwin.f_Set("INIT");
    scwin.f_DefaultValue();
    scwin.processFlag = "INIT";
    if (scwin.mblno !== ("")){
        scwin.f_Retrieve();
    }
    lc_vatYn.focus();
    scwin.f_MhnoLoading("M",ed_mblno.getValue().trim())
}



//-------------------------------------------------------------------------
// function name : f_DefaultValue
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
    if(scwin.kcomcd != ""){
        scwin.hid_kcomcd = scwin.kcomcd;
    }else{
        scwin.hid_kcomcd = "DBEX"
    }

    ed_mblno.setValue(scwin.mblno);
    ed_bilgClntNo.setValue(scwin.bilgClntNo);
    ed_dateFrom.setValue(scwin.strPreDate);
    ed_dateTo.setValue(scwin.strCurDate);

    if(ed_mblno.getValue()!=""){
        scwin.f_MhnoLoading("M",ed_mblno.getValue());		
    }

    lc_mhno.setValue(scwin.mhno);
    dma_searchFreight.set("kcomcd", scwin.hid_kcomcd);
    ///임시
    /*
    ed_dateFrom.setValue("20100101");
    ed_dateTo.setValue("20100201");
    */
    ///임시
}

//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function( gubun ) {
    switch ( gubun ) {    
        case "INIT" : //초기화
            $c.gus.cfDisableKeyData();
            btn_Save.setDisabled(true);
            btn_Delete.setDisabled(true);
            // $c.gus.cfDisableBtnOnly([btn_Save,btn_Delete]);
            scwin.f_DisablePopUpObj();
            break;
        case "RETRIEVE" :  //조회모드	
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            if(scwin.processFlag =="RETRIEVE"){
                // $c.gus.cfEnableBtnOnly([btn_Save, btn_Delete]);
                btn_Save.setDisabled(false);
                btn_Delete.setDisabled(false);
            }
            break;
        case "CANCEL" :	//취소
            scwin.f_Set("RETRIEVE");           	
            break; 
        case "CREATE" : //신규
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            // $c.gus.cfDisableBtnOnly([btn_Delete]);
            btn_Delete.setDisabled(true);
            // $c.gus.cfEnableBtnOnly([btn_Save]);  
            btn_Save.setDisabled(false);     	
            //gr_arrivalNoticeList.setDisabled(false);    
            break;
        case "UPDATE" :
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            // $c.gus.cfDisableBtnOnly([btn_Delete]);
            btn_Save.setDisabled(true);
            // $c.gus.cfEnableBtnOnly([btn_Save]);
            btn_Save.setDisabled(false);
            break;    
        case "SAVE" :
            // $c.gus.cfDisableBtnOnly([btn_Save]);
            btn_Save.setDisabled(true);
            // $c.gus.cfEnableBtnOnly([ btn_Delete]);
            btn_Delete.setDisabled(false);
            scwin.f_Set("RETRIEVE");
            break;                
        case "DELETE" :
            $c.gus.cfDisableBtnOnly([btn_Save]);
            btn_Save.setDisabled(true);
            $c.gus.cfEnableBtnOnly([btn_Delete]);
            btn_Delete.setDisabled(false);
            scwin.f_Set("RETRIEVE");
            break;                   
    }
} 

//-------------------------------------------------------------------------
// PopUp 이미지를 활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function () {

}

//-------------------------------------------------------------------------
// PopUp 이미지를 비활성화 시킨다. 
