//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
    if(ed_dateFrom.getValue().trim()=='' || ed_dateTo.getValue().trim()==''){
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, Array("ETD/ETA"));
        ed_dateFrom.focus();
        return;
    }

    //dataset clear
    ds_invoiceCommon.removeAll();
    ds_invoiceFreight.removeAll();

    $c.sbm.execute(sbm_retrieve);
}

//-------------------------------------------------------------------------
// 운임 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveCommon = function () {		
    ds_invoiceCommon.removeAll();
    ds_invoiceFreight.removeAll();

    $c.sbm.execute(sbm_retrieveCommon);
}

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function () {
    scwin.f_Set("CREATE");  
    ica_bilgIntendDt.focus();
}

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    scwin.f_Set("UPDATE");  
    ica_bilgIntendDt.focus();
}

//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Undo = function () {
    ds_invoiceCommon.removeAll();
    ds_invoiceFreight.removeAll();
    scwin.f_Set("CANCEL");
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {    

    if (ds_invoiceCommon.getRowCount()<1) {
        //$c.win.alert(MSG_CM_ERR_056, new Array("Invoice")); //let MSG_CM_ERR_056   =  "선택된 @이(가) 없습니다.";
        $c.win.alert("선택된 Invoice이(가) 없습니다.");
        return ;
    }

    if (ds_invoiceFreight.getRowCount()<1) {
        //$c.win.alert(MSG_CM_ERR_056, new Array("Invoice")); //@는 변경된 사항이 없습니다.
        $c.win.alert("선택된 Invoice이(가) 없습니다.");
        return ;
    }

    if (await scwin.f_ReqFieldChk()) {
        if (await $c.win.confirm(MSG_CM_CRM_001)) {
            $c.sbm.execute(sbm_save);
            scwin.processFlag = "RETRIEVE";
            scwin.f_Set("RETRIEVE");
        }
    }
}


//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
    //alert(ds_invoiceCommon.getCellData(ds_invoiceCommon.rowPosition, "chk"));
    var cnt = 0;
    for (var i = 0; i < ds_invoiceCommon.getRowCount(); i++)	{
        //if(ds_invoiceCommon.getCellData(ds_invoiceCommon.getRowPosition(), "chk") == "T"){
        if(ds_invoiceCommon.getCellData(i, "chk") == "T"){            
            cnt++;
        }

    }
    if(cnt == 0)	{
        $c.win.alert("선택된 거래명세서가 없습니다. ");
        return;
    }
    if (await $c.win.confirm(MSG_CM_CRM_004)) {	//삭제하시겠습니까?

        let cf = ds_invoiceCommon.getRowCount();

        for(let i=0;i<=cf;i++){
            ds_invoiceCommon.setRowPosition(i)
            //alert(ds_invoiceCommon.getCellData(i, "chk"));
            if(ds_invoiceCommon.getCellData(i, "chk")=="T"){
                ds_invoiceCommon.setCellData(i, "chk", "K");
            }
        }
        $c.sbm.execute(sbm_save);
    }
}

//-------------------------------------------------------------------------
// Validate check
//-------------------------------------------------------------------------
scwin.f_ReqFieldChk = async function () {
    if (await $c.gus.cfValidate([oDetailInfo]) == false) {
        return false;
    }
    //grid valid x
    // if (await $c.gus.cfValidate([gr_invoiceFreightList]) == false) {
    //     return false;
    // }
    return true;
}

