            rtnList = udc_engClntInfo.ilCommonPopUp(scwin.udc_engClntInfo_callBackFunc, ed_bilgClntNo.getValue().trim(),  
                                    ed_bilgClntNm.getValue(),       
                                    chgGubun,                       
                                    '5',                            
                                    'Customer',                 	
                                    '140,300',                      
                                    null,                           
                                    null,                           
                                    '500',                          
                                    '500',                          
                                    null,                           
                                    null,                           
                                    null,                           
                                    'F',                            
                                    'Customer Search,Customer Code,Customer Name');

            // cfSetReturnValue(rtnList, ed_bilgClntNo, ed_bilgClntNm);

            break;					

        case 2:		//거래처 담당자 팝업(PIC)
            rtnList = udc_clntPicInfo.ilCommonPopUp(scwin.udc_clntPicInfo_callBackFunc, ed_anno.getValue().trim(),  
                                    ed_annm.getValue(),       
                                    chgGubun,             
                                    '4',                  
                                    "PIC", 		          
                                    //'80,200,120,300',   
                                    '100,350',            
                                    null,                 
                                    pParam,               
                                    '500',                
                                    '500',                
                                    null,                 
                                    null,                 
                                    null,                 
                                    "T",                  
                                    null);				

            // cfSetReturnValue(rtnList, ed_anno, ed_annm, ed_bilgClntNo);
            _new.close();

            break;

        case 3: 
            rtnList = udc_opDeptCdInfo.ilCommonPopUp(scwin.udc_opDeptCdInfo_callBackFunc, ed_dept.getValue().trim()
                                    ,ed_deptnm.getValue()
                                    ,"T"
                                    ,'2'
                                    ,"Code, Name"
                                    ,'80,230'
                                    ,"3,4,5,6,7,8,9,10"
                                    ,null ,null ,null ,null ,null ,null
                                    ,"F"
                                    ,"Department,Code,Name"
                                    ,"F"); 

                // cfSetReturnValue(rtnList, ed_dept, ed_deptnm);
            break;	

        default:
            break;
    }

}

// ======================
// 콜백 함수들
// ======================
scwin.udc_engClntInfo_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_bilgClntNo.setValue(rtnList[0]);
        ed_bilgClntNm.setValue(rtnList[1]);
        ed_bilgClntNo.options.hidVal = rtnList[0];
        ed_bilgClntNm.options.hidVal = rtnList[1];
    } else {
        ed_bilgClntNo.setValue("");
        ed_bilgClntNm.setValue("");
        ed_bilgClntNo.options.hidVal = "";
        ed_bilgClntNm.options.hidVal = "";
    }
};

scwin.udc_clntPicInfo_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_anno.setValue(rtnList[0]);
        ed_annm, ed_bilgClntNo.setValue(rtnList[1]);
        ed_anno.options.hidVal = rtnList[0];
        ed_annm, ed_bilgClntNo.options.hidVal = rtnList[1];
    } else {
        ed_anno.setValue("");
        ed_annm, ed_bilgClntNo.setValue("");
        ed_anno.options.hidVal = "";
        ed_annm, ed_bilgClntNo.options.hidVal = "";
    }
};

scwin.udc_opDeptCdInfo_callBackFunc = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_dept.setValue(rtnList[0]);
        ed_deptnm.setValue(rtnList[1]);
        ed_dept.options.hidVal = rtnList[0];
        ed_deptnm.options.hidVal = rtnList[1];
    } else {
        ed_dept.setValue("");
        ed_deptnm.setValue("");
        ed_dept.options.hidVal = "";
        ed_deptnm.options.hidVal = "";
    }
};


//MHNNO 가져오기
scwin.f_MhnoLoading = function(mhgb,blno){
    let strClntNo = "";
    strClntNo = blno;

    if (strClntNo.length > 0) {	
        param1 = strClntNo;
        sbm_ds_mhno.action = "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveAirMasterMhnoListCombo&param1=" + param1;
        $c.sbm.execute(sbm_ds_mhno);	
    }
}

