//-------------------------------------------------------------------------
//  세금계산서 생성 팝업
//-------------------------------------------------------------------------  
scwin.f_SlipPopUp = async function () {

    var cf = ds_invoiceCommon.getRowCount();


    for(var i =0; i < cf; i++) {
        ds_invoiceCommon.setRowPosition(i);
        if(ds_invoiceCommon.getCellData(i, "chk")=="T"){
            if(ds_invoiceCommon.getCellData(ds_invoiceCommon.getRowPosition(), "prtnGrpNo") != "") {
                /*
                let style = "center:yes; dialogwidth:630px; dialogheight:710px; scroll:no; resizable:no; status:yes;";
                let strPath = "/ui/ds/fs/bilg/fs_202_06_03p.jsp";
                let pram = new Array(1);
                $c.gus.cfCopyDataSet(ds_invoiceCommon, ds_certiCommonDs, "copyHeader=yes");
                //Radio Value	- 청구/영수
                //alert(ds_invoiceCommon.getCellData(i, "slipNo"));

                ds_certiCommonDs.setCellData(0, "receptClsCd", "02");
                ds_certiCommonDs.setCellData(0, "slipNo", ds_invoiceCommon.getCellData(i, "slipNo"));

                pram[0] = ds_certiCommonDs;
                pram[1] = scwin.hid_commNm;

                //alert(pram[1]);
                //pram[1] = ds_certidetail.getCellData(1, "certiInscrpSellItemNm");

                let	returnValue = window.showModalDialog(strPath, pram, style) ;	
                */

                //$c.gus.cfCopyDataSet(ds_invoiceCommon, ds_certiCommonDs, "copyHeader=yes");
                //console.log(ds_invoiceCommon.getRowJSON(i));
                ds_certiCommonDs.removeAll();
                ds_certiCommonDs.insertRow(0);
                ds_certiCommonDs.setRowJSON(0, ds_invoiceCommon.getRowJSON(i), true);
                ds_certiCommonDs.setCellData(0, "receptClsCd", "02");
                ds_certiCommonDs.setCellData(0, "slipNo", ds_invoiceCommon.getCellData(i, "slipNo"));

                var win_url = "/ui/ds/fs/bilg/fs_202_06_03p.xml";

                var opts = scwin.opts || {};
                opts.modal = true;
                opts.type = "browserPopup";
                opts.id = scwin.popupID || "pupup";
                opts.width = 1100;
                opts.height = 650;
                opts.popupName = '세금계산서 생성';

                var param = {
                    "ds_certiCommon" : ds_certiCommonDs,
                    hid_commNm : scwin.hid_commNm
                }


                returnValue = await $c.win.openPopup(win_url, opts, param);
                console.log("returnValue : " , returnValue);


                if(returnValue[0] != undefined && returnValue[0] != null){
                    scwin.dtl_sellVatNo = returnValue[0];
                } 
                if(returnValue[1] == "TRUE") {
                    scwin.f_Retrieve();
                }
            } else {
                await $c.win.alert(MSG_FS_WRN_002);
                return;
            }	
        }
    }
}


//-------------------------------------------------------------------------
// 세금계산서일괄생성 이동
//-------------------------------------------------------------------------  
scwin.f_SlipCreate = function () {
    let cf = ds_invoiceCommon.getRowCount();
    let bilgLodeptCd = "";
    let bilgLodeptNm = "";
    let bilgClntNo = "";
    let bilgClntNm = "";
    let certiPatternCd = "";
    let qryConDtFm = "";
    let qryConDtTo = "";
    let taxnClsCd = "";

    for(let i=0;i<=cf;i++){
        ds_invoiceCommon.setRowPosition(i);
        if(ds_invoiceCommon.getCellData(i, "chk")=="T"){
            bilgLodeptCd		= ds_invoiceCommon.getCellData(i, "bilgLodeptCd");
            bilgLodeptNm		= "";

            bilgClntNo			= ds_invoiceCommon.getCellData(i, "bilgClntNo");
            bilgClntNm			= ds_invoiceCommon.getCellData(i, "bilgClntNm");

            certiPatternCd		= "04";
            qryConDtFm			= ica_bilgIntendDt.getValue().trim();
            qryConDtTo			= ica_bilgIntendDt.getValue().trim();

            taxnClsCd			= "01";
            if(ds_invoiceCommon.getCellData(i, "vatAmt") == 0){
                taxnClsCd			= "02";
            }
        }
    }

    // 전자세금계산서 URL 연결을 위한 파라메터
    let kcomcd = ds_invoiceFreight.getCellData(ds_invoiceFreight.getRowPosition(), "kcomcd");
    let seaair = ds_invoiceFreight.getCellData(ds_invoiceFreight.getRowPosition(), "seaair");
    let iogb = ds_invoiceFreight.getCellData(ds_invoiceFreight.getRowPosition(), "iogb");
    let userId = ds_invoiceFreight.getCellData(ds_invoiceFreight.getRowPosition(), "modId");
    let type = "0";
    let rmk = "N";
    let eng = "1";
    let locPtnCls = "1";
    let pic = 2; 

    /* 
    param = "?bilgLodeptCd="+bilgLodeptCd+"&bilgLodeptNm="+bilgLodeptNm
    param = param + "&bilgClntNo="+bilgClntNo+"&bilgClntNm="+bilgClntNm
    param = param + "&certiPatternCd="+certiPatternCd
    param = param + "&qryConDtFm="+qryConDtFm+"&qryConDtTo="+qryConDtTo+"&taxnClsCd="+taxnClsCd
    param = param + "&kcomcd="+kcomcd+"&seaair="+seaair+"&iogb="+iogb+"&userId="+userId
    param = param + "&type="+type+"&rmk="+rmk+"&eng="+eng+"&locPtnCls="+locPtnCls+"&pic="+pic
    */

    var param = {
        bilgLodeptCd    : bilgLodeptCd,
        bilgLodeptNm    : bilgLodeptNm,
        bilgClntNo      : bilgClntNo,
        bilgClntNm      : bilgClntNm,
        certiPatternCd  : certiPatternCd,
        qryConDtFm      : qryConDtFm,
        qryConDtTo      : qryConDtTo,
        taxnClsCd       : taxnClsCd,
        kcomcd          : kcomcd,
        seaair          : seaair,
        iogb            : iogb,
        userId          : userId,
        type            : type,
        rmk             : rmk,
        eng             : eng,
        locPtnCls       : locPtnCls,
        pic             : pic
    };

    let strPath = "/ui/ds/fs/bilg/fs_202_06_05b.xml";

    // cfTabMenuUpdate( strPath , "청구세금계산서일괄생성");
    $c.win.openMenu("청구세금계산서일괄생성", strPath, "fs_202_06_05b",param);

}

//-------------------------------------------------------------------------
// 확인일자 처리
//-------------------------------------------------------------------------
scwin.f_Confirm = function () {
    let confirmDt = "";
    confirmDt = ica_bilgIntendDt.getValue().trim();
    if (confirmDt.length > 0) {	
        for (i = 0; i < ds_invoiceCommon.getRowCount(); i++){
            if(ds_invoiceCommon.getCellData(i, "chk")=="T"){
                ds_invoiceCommon.setCellData(i, "confirmDt", confirmDt);
                ds_invoiceCommon.setCellData(i, "bilgIntendDt", confirmDt);
            }
        }
    } else {
        ica_bilgIntendDt.setValue("");
    }
}  	



