scwin.gr_invoiceFreightList_onviewchange = function (info) {
	let vatCnt = 0;
    let row = info.rowIndex
    let colid = info.colId

	if(ds_invoiceFreight.getRowCount()>0){

		let confirmDt = ica_bilgIntendDt.getValue().trim();


    	if(colid =="chk"){
    		refkey = ds_invoiceFreight.getCellData(row, "refkey");
			for (i = 0; i < ds_invoiceFreight.getRowCount(); i++){
	        	if(ds_invoiceFreight.getCellData(i, "chk")=="T" && refkey == ds_invoiceFreight.getCellData(i, "refkey")){
	          		vatCnt = vatCnt + 1;
	         	}
	     	}

	     	//alert(vatCnt);
	     	//alert(refkey);
	     	if(vatCnt<1){	
				for (i = 0; i < ds_invoiceCommon.getRowCount(); i++){
					//alert("aaa==>"+ds_invoiceCommon.getCellData(i, "refkey"));
					if(ds_invoiceCommon.getCellData(i, "chk")=="T" && refkey == ds_invoiceCommon.getCellData(i, "refkey")){
	          			ds_invoiceCommon.setCellData(i, "chk", "F");

	          			ds_invoiceCommon.setCellData(i, "confirmDt", "");
		       			ds_invoiceCommon.setCellData(i, "bilgIntendDt", "");
	         		}
				}
	     	}else{
	     		for (i = 0; i < ds_invoiceCommon.getRowCount(); i++){
					//alert("bbb==>"+ds_invoiceCommon.getCellData(i, "refkey"));
					if(ds_invoiceCommon.getCellData(i, "chk")=="F" && refkey == ds_invoiceCommon.getCellData(i, "refkey")){
	          			ds_invoiceCommon.setCellData(i, "chk", "T");
                        console.log(ds_invoiceCommon.getCellData(i, "chk"));
	          			ds_invoiceCommon.setCellData(i, "confirmDt", confirmDt);
		       			ds_invoiceCommon.setCellData(i, "bilgIntendDt", confirmDt);
	         		}
				}
	     	}
	 	}
   	}  
};




